// Constants
const ERROR_TYPES = {
  VALIDATION_FAILED: 'ValidationFailed',
  PROCESSING_ERROR: 'ProcessingError',
  DATA_TRANSFORMATION_ERROR: 'DataTransformationError',
  SALESFORCE_API_ERROR: 'SalesforceApiError',
  AUTHENTICATION_ERROR: 'AuthenticationError',
  AUTHORIZATION_ERROR: 'AuthorizationError',
  RESOURCE_NOT_FOUND: 'ResourceNotFound',
  RATE_LIMIT_ERROR: 'RateLimitError',
  SERVER_ERROR: 'ServerError',
  SERVICE_UNAVAILABLE: 'ServiceUnavailable',
  RECORD_LOCK_ERROR: 'RecordLockError',
  DUPLICATE_ERROR: 'DuplicateError',
  BATCH_ERROR: 'BatchError',
  TIMEOUT_ERROR: 'TimeoutError'
};

const HTTP_STATUS_TO_ERROR_TYPE = {
  400: ERROR_TYPES.VALIDATION_FAILED,
  401: ERROR_TYPES.AUTHENTICATION_ERROR,
  403: ERROR_TYPES.AUTHORIZATION_ERROR,
  404: ERROR_TYPES.RESOURCE_NOT_FOUND,
  405: ERROR_TYPES.VALIDATION_FAILED,
  409: ERROR_TYPES.DUPLICATE_ERROR,
  412: ERROR_TYPES.BATCH_ERROR,
  415: ERROR_TYPES.VALIDATION_FAILED,
  500: ERROR_TYPES.SERVER_ERROR,
  502: ERROR_TYPES.SERVER_ERROR,
  503: ERROR_TYPES.SERVICE_UNAVAILABLE
};

const SALESFORCE_ERROR_CODES = {
  INVALID_SESSION_ID: ERROR_TYPES.AUTHENTICATION_ERROR,
  REQUEST_LIMIT_EXCEEDED: ERROR_TYPES.RATE_LIMIT_ERROR,
  UNABLE_TO_LOCK_ROW: ERROR_TYPES.RECORD_LOCK_ERROR,
  DUPLICATE_VALUE: ERROR_TYPES.DUPLICATE_ERROR,
  ENTITY_IS_DELETED: ERROR_TYPES.RESOURCE_NOT_FOUND,
  REQUIRED_FIELD_MISSING: ERROR_TYPES.VALIDATION_FAILED,
  INVALID_FIELD: ERROR_TYPES.VALIDATION_FAILED,
  MALFORMED_ID: ERROR_TYPES.VALIDATION_FAILED,
  INVALID_FIELD_FOR_INSERT_UPDATE: ERROR_TYPES.VALIDATION_FAILED,
  FIELD_CUSTOM_VALIDATION_EXCEPTION: ERROR_TYPES.VALIDATION_FAILED,
  INVALID_BATCH_SIZE: ERROR_TYPES.BATCH_ERROR,
  ALL_OR_NONE_OPERATION_ROLLED_BACK: ERROR_TYPES.BATCH_ERROR,
  QUERY_TIMEOUT: ERROR_TYPES.TIMEOUT_ERROR,
  EXCEEDED_MAX_SIZE_REQUEST: ERROR_TYPES.VALIDATION_FAILED
};

/**
 * Main orchestration function - processes Salesforce composite API responses
 */
exports.step = function(input) {
  try {
    if (!input) {
      return createSingleErrorOutput(
        ERROR_TYPES.VALIDATION_FAILED,
        'Input is required',
        'Input validation'
      );
    }

    const responses = extractResponseArray(input);
    const successfulResponses = extractSuccessfulResponses(responses);
    const failedResponses = extractFailedResponses(responses);
    const errors = createStandardizedErrors(failedResponses);
    const summary = createResponseSummary(responses, successfulResponses, failedResponses);
    const processedResults = extractProcessedResults(successfulResponses);

    return {
      successful_operations: processedResults,
      errors: errors,
      summary: summary,
      total_responses: responses.length,
      processed_at: new Date().toISOString()
    };
  } catch (error) {
    return createSingleErrorOutput(
      ERROR_TYPES.PROCESSING_ERROR,
      error.message,
      'Main processing',
      { stackTrace: error.stack }
    );
  }
};

// Helper functions below
function extractResponseArray(input) {
  if (Array.isArray(input)) return input;
  if (input.results && Array.isArray(input.results)) return input.results;
  if (input.response && Array.isArray(input.response)) return input.response;
  if (input.compositeResponse && Array.isArray(input.compositeResponse)) return input.compositeResponse;
  if (input.httpStatusCode !== undefined || input.statusCode !== undefined) return [input];
  return [];
}

function extractSuccessfulResponses(responses) {
  return responses.filter(isSalesforceSuccessResponse);
}

function extractFailedResponses(responses) {
  return responses.filter(response => !isSalesforceSuccessResponse(response));
}

function isSalesforceSuccessResponse(response) {
  const statusCode = response.httpStatusCode || response.statusCode || 0;
  if (statusCode < 200 || statusCode >= 300) return false;
  if (response.body && response.body.success !== undefined) return response.body.success === true;
  if (response.body && Array.isArray(response.body) && response.body[0] && response.body[0].errorCode) return false;
  return true;
}

function extractProcessedResults(successfulResponses) {
  return successfulResponses.map(createProcessedResult);
}

function createProcessedResult(response) {
  const body = response.body || {};
  return {
    salesforce_id: body.id || null,
    reference_id: response.referenceId || null,
    operation_type: body.created ? 'created' : body.id ? 'updated' : 'processed',
    http_status: response.httpStatusCode || response.statusCode,
    location: response.httpHeaders && response.httpHeaders.Location ? response.httpHeaders.Location : null,
    success: body.success !== undefined ? body.success : true
  };
}

function createStandardizedErrors(failedResponses) {
  const allErrors = [];
  failedResponses.forEach(response => {
    const errorEntries = createSalesforceErrorEntries(response);
    allErrors.push(...errorEntries);
  });
  return allErrors;
}

function createSalesforceErrorEntries(response) {
  const errors = [];
  const referenceId = response.referenceId || 'Unknown';
  const statusCode = response.httpStatusCode || response.statusCode || 500;

  if (Array.isArray(response.body)) {
    response.body.forEach(error => {
      errors.push(createStandardizedSalesforceError(error, referenceId, statusCode));
    });
  } else if (response.body && Array.isArray(response.body.errors)) {
    response.body.errors.forEach(error => {
      errors.push(createStandardizedSalesforceError(error, referenceId, statusCode));
    });
  } else if (response.body && response.body.errorCode) {
    errors.push(createStandardizedSalesforceError(response.body, referenceId, statusCode));
  } else {
    const errorData = {
      errorCode: mapHttpStatusToSalesforceError(statusCode),
      message: getSalesforceHttpStatusMessage(statusCode)
    };
    errors.push(createStandardizedSalesforceError(errorData, referenceId, statusCode));
  }
  return errors;
}

function createStandardizedSalesforceError(errorData, referenceId, statusCode) {
  const errorCode = errorData.errorCode || 'UNKNOWN_ERROR';
  const errorType = determineSalesforceErrorType(errorCode, statusCode);
  const message = errorData.message || getSalesforceHttpStatusMessage(statusCode);
  const retryable = isRetryableError(errorCode, statusCode);
  const retryStrategy = getRetryStrategy(errorCode, statusCode);

  return {
    error: {
      response: {
        body: {
          Type: errorType,
          Message: message,
          ErrorCode: errorCode
        }
      },
      message: message,
      statusCode: statusCode,
      retryable: retryable,
      retryStrategy: retryStrategy
    },
    id: `Salesforce Operation Reference # ${referenceId}`,
    service: 'Salesforce Composite API Processing',
    fields: errorData.fields || []
  };
}

function determineSalesforceErrorType(errorCode, statusCode) {
  if (SALESFORCE_ERROR_CODES[errorCode]) return SALESFORCE_ERROR_CODES[errorCode];
  if (statusCode && HTTP_STATUS_TO_ERROR_TYPE[statusCode]) return HTTP_STATUS_TO_ERROR_TYPE[statusCode];
  return ERROR_TYPES.SALESFORCE_API_ERROR;
}

function isRetryableError(errorCode, statusCode) {
  const retryableErrorCodes = ['UNABLE_TO_LOCK_ROW', 'REQUEST_LIMIT_EXCEEDED', 'QUERY_TIMEOUT'];
  const retryableStatusCodes = [408, 429, 500, 502, 503, 504];
  return retryableErrorCodes.includes(errorCode) || retryableStatusCodes.includes(statusCode);
}

function getRetryStrategy(errorCode, statusCode) {
  const strategies = {
    UNABLE_TO_LOCK_ROW: {
      maxRetries: 3,
      delayMs: 2000,
      backoffMultiplier: 2,
      recommendation: 'Retry with exponential backoff, max 10 seconds wait'
    },
    REQUEST_LIMIT_EXCEEDED: {
      maxRetries: 0,
      delayMs: null,
      backoffMultiplier: 1,
      recommendation: 'Wait until 24-hour window resets or increase API limits'
    },
    INVALID_SESSION_ID: {
      maxRetries: 1,
      delayMs: 0,
      backoffMultiplier: 1,
      recommendation: 'Re-authenticate and retry once'
    },
    QUERY_TIMEOUT: {
      maxRetries: 2,
      delayMs: 5000,
      backoffMultiplier: 1.5,
      recommendation: 'Optimize query or reduce result set size'
    }
  };

  if (strategies[errorCode]) return strategies[errorCode];
  if (statusCode === 503 || statusCode === 502) {
    return {
      maxRetries: 3,
      delayMs: 1000,
      backoffMultiplier: 2,
      recommendation: 'Service temporarily unavailable, retry with backoff'
    };
  }

  return {
    maxRetries: 0,
    delayMs: null,
    backoffMultiplier: 1,
    recommendation: 'Not retryable, fix error and resubmit'
  };
}

function mapHttpStatusToSalesforceError(statusCode) {
  const statusMappings = {
    400: 'VALIDATION_EXCEPTION',
    401: 'INVALID_SESSION_ID',
    403: 'INSUFFICIENT_ACCESS',
    404: 'NOT_FOUND',
    405: 'METHOD_NOT_ALLOWED',
    409: 'DUPLICATE_VALUE',
    412: 'PRECONDITION_FAILED',
    415: 'UNSUPPORTED_MEDIA_TYPE',
    429: 'REQUEST_LIMIT_EXCEEDED',
    500: 'INTERNAL_SERVER_ERROR',
    502: 'BAD_GATEWAY',
    503: 'SERVICE_UNAVAILABLE',
    504: 'GATEWAY_TIMEOUT'
  };
  return statusMappings[statusCode] || 'UNSPECIFIED_ERROR';
}

function getSalesforceHttpStatusMessage(statusCode) {
  const statusMessages = {
    400: 'Bad request - request contains invalid data or formatting',
    401: 'Authentication session is invalid or expired',
    403: 'User lacks permission to perform this operation',
    404: 'Requested resource or record was not found',
    405: 'HTTP method not allowed for this resource',
    409: 'Duplicate value found for unique field',
    412: 'Precondition failed - batch processing halted',
    415: 'Unsupported media type',
    429: 'API request limits have been exceeded',
    500: 'Internal server error occurred during processing',
    502: 'Bad gateway - upstream server error',
    503: 'Service temporarily unavailable',
    504: 'Gateway timeout - request took too long'
  };
  return statusMessages[statusCode] || 'An unknown error occurred during processing';
}

function createResponseSummary(allResponses, successfulResponses, failedResponses) {
  const createdOperations = successfulResponses.filter(response =>
    response.body && response.body.created === true
  );
  const updatedOperations = successfulResponses.filter(response =>
    response.body && response.body.id && response.body.created === false
  );

  return {
    total_operations: allResponses.length,
    successful_operations: successfulResponses.length,
    failed_operations: failedResponses.length,
    records_created: createdOperations.length,
    records_updated: updatedOperations.length,
    success_rate: allResponses.length > 0
      ? Math.round((successfulResponses.length / allResponses.length) * 100)
      : 0
  };
}

function createSingleErrorOutput(errorType, message, context, additionalInfo) {
  const errorObject = {
    error: {
      response: {
        body: {
          Type: errorType,
          Message: message,
          ErrorCode: 'SCRIPT_ERROR'
        }
      },
      message: message,
      statusCode: 500,
      retryable: false,
      retryStrategy: {
        maxRetries: 0,
        delayMs: null,
        backoffMultiplier: 1,
        recommendation: 'Fix script error and retry'
      }
    },
    id: `Script Error in ${context}`,
    service: 'Tray Script Processing',
    timestamp: new Date().toISOString()
  };

  if (additionalInfo) {
    errorObject.error.details = additionalInfo;
  }

  return {
    successful_operations: [],
    errors: [errorObject],
    summary: {
      total_operations: 0,
      successful_operations: 0,
      failed_operations: 1,
      records_created: 0,
      records_updated: 0,
      success_rate: 0
    },
    total_responses: 0,
    processed_at: new Date().toISOString()
  };
}

