/**
 * Transform data using lookup maps for efficient O(1) access
 */
exports.step = function(input, fileInput) {
  const { gpa_data, namespace_prefix, ohfy_products, ohfy_accounts } = input;

  const productLookup = buildProductLookup(ohfy_products);
  const accountLookup = buildAccountLookup(ohfy_accounts);
  const csvRows = createCsvRows(gpa_data, namespace_prefix, productLookup, accountLookup);
  const validRows = filterValidRows(csvRows);
  const nullItemIds = findNullItemIds(csvRows, gpa_data, namespace_prefix);
  const productErrors = generateDeduplicatedProductErrors(csvRows, gpa_data);
  const accountErrors = generateDeduplicatedAccountErrors(csvRows, gpa_data);
  const allErrors = [...productErrors, ...accountErrors];
  const summary = createProcessingSummary(gpa_data, validRows, allErrors);

  return {
    rows: validRows,
    ids: nullItemIds,
    errors: allErrors,
    summary: summary
  };
};

// Helper functions below exports.step
function buildProductLookup(ohfyProducts) {
  return ohfyProducts
    .filter(hasValidProductMapping)
    .reduce((lookup, product) => ({
      ...lookup,
      [product.Original_ID__c]: product.Product__c
    }), {});
}

function buildAccountLookup(ohfyAccounts) {
  return ohfyAccounts
    .filter(hasValidAccountMapping)
    .reduce((lookup, account) => ({
      ...lookup,
      [account.Original_ID__c]: account.Account__c
    }), {});
}

function hasValidProductMapping(product) {
  return product.Original_ID__c && product.Product__c;
}

function hasValidAccountMapping(account) {
  return account.Original_ID__c && account.Account__c;
}

function createCsvRows(gpaData, namespacePrefix, productLookup, accountLookup) {
  return gpaData.map(item => createSingleCsvRow(item, namespacePrefix, productLookup, accountLookup));
}

function createSingleCsvRow(item, namespacePrefix, productLookup, accountLookup) {
  return {
    External_ID__c: item.id,
    Item__c: productLookup[item.product_gpa_id] || null,
    Account__c: accountLookup[item.buyer_id] || null,
    Week__c: item.week,
    Year__c: item.year,
    Week_Start__c: item.calculated_start_of_date_range,
    Week_End__c: item.calculated_end_of_date_range,
    Sales_Rate_Per_Week__c: item.sales_rate_per_week,
    Initial_Sales_Rate_Per_Week__c: item.initial_sales_rate_per_week,
    On_Hand_Begin__c: item.on_hand_begin,
    Inbound_Units__c: item.inbound_units,
    Net_Days__c: item.net_days,
    Days_On_Hand__c: item.days_on_hand
  };
}

function filterValidRows(csvRows) {
  return csvRows.filter(row => row['Item__c'] !== null && row['Account__c'] !== null);
}

function findNullItemIds(csvRows, gpaData, namespacePrefix) {
  const nullRows = filterNullItems(csvRows, namespacePrefix);
  const nullIds = extractExternalIds(nullRows, namespacePrefix);
  const nullItems = createNullItemDescriptions(gpaData, nullIds);
  return getUniqueItems(nullItems);
}

function filterNullItems(csvRows, namespacePrefix) {
  return csvRows.filter(row => row['Item__c'] === null);
}

function extractExternalIds(nullRows, namespacePrefix) {
  return nullRows.map(row => row['External_ID__c']);
}

function createNullItemDescriptions(gpaData, nullIds) {
  return gpaData
    .filter(item => nullIds.includes(item.id))
    .map(formatItemDescription);
}

function formatItemDescription(item) {
  return `${item.product_gpa_id}:${item.brand_name}-${item.package_size}`;
}

function getUniqueItems(items) {
  return [...new Set(items)];
}

function generateDeduplicatedProductErrors(csvRows, gpaData) {
  const missingProductRows = csvRows.filter(row => row['Item__c'] === null);
  const productIdCounts = countMissingProductIds(missingProductRows, gpaData);

  return Object.entries(productIdCounts).map(([productId, count]) =>
    createMissingProductError(productId, count)
  );
}

function generateDeduplicatedAccountErrors(csvRows, gpaData) {
  const missingAccountRows = csvRows.filter(row => row['Account__c'] === null);
  const accountIdCounts = countMissingAccountIds(missingAccountRows, gpaData);

  return Object.entries(accountIdCounts).map(([accountId, count]) =>
    createMissingAccountError(accountId, count)
  );
}

function countMissingProductIds(missingRows, gpaData) {
  return missingRows.reduce((counts, row) => {
    const gpaItem = gpaData.find(item => item.id === row['External_ID__c']);
    const productId = gpaItem.product_gpa_id;
    counts[productId] = (counts[productId] || 0) + 1;
    return counts;
  }, {});
}

function countMissingAccountIds(missingRows, gpaData) {
  return missingRows.reduce((counts, row) => {
    const gpaItem = gpaData.find(item => item.id === row['External_ID__c']);
    const accountId = gpaItem.buyer_id;
    counts[accountId] = (counts[accountId] || 0) + 1;
    return counts;
  }, {});
}

function createMissingProductError(productId, count) {
  return {
    error: {
      response: {
        body: {
          Type: "UnmatchedProductMapping",
          Message: "Product mapping failed - no matching product found in lookup"
        }
      },
      message: "Product mapping failed - no matching product found in lookup",
      statusCode: 500
    },
    id: `GPA Product ID # ${productId}`,
    service: "GPA to Ohanafy Item Forecast Processing"
  };
}

function createMissingAccountError(accountId, count) {
  return {
    error: {
      response: {
        body: {
          Type: "UnmatchedAccountMapping",
          Message: "Account mapping failed - no matching account found in lookup"
        }
      },
      message: "Account mapping failed - no matching account found in lookup",
      statusCode: 500
    },
    id: `GPA Buyer ID # ${accountId}`,
    service: "GPA to Ohanafy Item Forecast Processing"
  };
}

function createProcessingSummary(gpaData, validRows, allErrors) {
  const totalProcessed = gpaData.length;
  const successful = validRows.length;
  const errorCount = totalProcessed - successful;

  return [
    {
      metric: "Total Rows Processed",
      count: totalProcessed
    },
    {
      metric: "Successful Rows",
      count: successful
    },
    {
      metric: "Error Rows",
      count: errorCount
    },
    {
      metric: "Unique Error Types",
      count: allErrors.length
    }
  ];
}

