exports.step = function({orderResults, orderItemResults, totalRows, dataErrors, apiErrors}, fileInput) {
  const errors = [];
  if (dataErrors.length > 0) errors.push(...dataErrors);
  if (apiErrors.length > 0) errors.push(...apiErrors);

  let orderStats = orderResults.reduce((accumulator, currentObject) => {
    Object.keys(currentObject).forEach(key => {
      accumulator[key] = (accumulator[key] || 0) + currentObject[key];
    });
    return accumulator;
  }, {});

  let orderItemStats = orderItemResults.reduce((accumulator, currentObject) => {
    Object.keys(currentObject).forEach(key => {
      accumulator[key] = (accumulator[key] || 0) + currentObject[key];
    });
    return accumulator;
  }, {});

  // Helper function to calculate percentage
  const calculatePercentage = (value, total) => {
    return total > 0 ? ((value / total) * 100).toFixed(1) : '0.0';
  };

  // Calculate success and error totals
  const successTotal = orderItemStats.created + orderItemStats.updated;
  const errorTotal = orderItemStats.dataErrors + orderItemStats.apiErrors;

  const hasApiErrors = (
    orderItemStats.apiErrors > 0 
    || orderStats.apiErrors > 0
  ) ? true : false;

  let message = `Hi there, \n\nYour data from has been uploaded to Ohanafy. Attached is a list of the results associated with the upload.\n\nCheers,\nOhanafy Integrations Team`;

