/**
 * Minimal orchestration pattern - all logic delegated to helpers
 */
exports.step = function(input, fileInput) {
  // Validate input
  if (!input) {
    return createErrorResponse('Input is required');
  }

  // Orchestrate processing through helpers
  const validated = validateInput(input);
  const processed = processData(validated);
  const summary = createSummary(processed);

  return {
    data: processed,
    summary: summary,
    processed_at: new Date().toISOString()
  };
};

// All helper functions defined below exports.step
function validateInput(input) {
  const required = ['data', 'config'];
  const missing = required.filter(field => !input[field]);

  if (missing.length > 0) {
    throw new Error(`Missing required fields: ${missing.join(', ')}`);
  }

  return input;
}

function processData(input) {
  const items = input.data || [];

  return items
    .filter(isValidItem)
    .map(transformItem)
    .map(enrichItem);
}

function isValidItem(item) {
  return item && item.id && item.active === true;
}

function transformItem(item) {
  return {
    ...item,
    processed: true,
    timestamp: new Date().toISOString()
  };
}

function enrichItem(item) {
  return {
    ...item,
    calculated_value: calculateValue(item),
    category: determineCategory(item)
  };
}

function calculateValue(item) {
  return (item.quantity || 0) * (item.price || 0);
}

function determineCategory(item) {
  if (item.priority === 'high') return 'urgent';
  if (item.priority === 'medium') return 'standard';
  return 'routine';
}

function createSummary(processed) {
  return {
    total_processed: processed.length,
    by_category: groupByCategory(processed),
    total_value: processed.reduce((sum, item) => sum + item.calculated_value, 0)
  };
}

function groupByCategory(items) {
  return items.reduce((groups, item) => {
    const category = item.category;
    groups[category] = (groups[category] || 0) + 1;
    return groups;
  }, {});
}

function createErrorResponse(message) {
  return {
    success: false,
    error: {
      message: message,
      timestamp: new Date().toISOString()
    }
  };
}

