/**
 * Build configuration object with defaults and overrides
 */
exports.step = function(input, fileInput) {
  const config = buildConfiguration(input);
  const validated = validateConfiguration(config);

  return {
    config: validated,
    is_valid: true
  };
};

// Helper functions below
const DEFAULT_CONFIG = {
  timeout: 30000,
  retries: 3,
  batchSize: 100,
  enableLogging: true
};

function buildConfiguration(input) {
  const base = {
    ...DEFAULT_CONFIG,
    ...input.overrides
  };

  return {
    ...base,
    ...(input.enableAdvanced && { advancedFeatures: input.advancedOptions }),
    ...(input.customEndpoint && { endpoint: input.customEndpoint }),
    environment: input.environment || 'production',
    createdAt: new Date().toISOString()
  };
}

function validateConfiguration(config) {
  if (config.timeout < 1000) {
    config.timeout = 1000;
  }

  if (config.retries < 0) {
    config.retries = 0;
  }

  if (config.batchSize > 1000) {
    config.batchSize = 1000;
  }

  return config;
}

