/**
 * Chunk large arrays for payload size limits
 */
exports.step = function(input, fileInput) {
  const items = input.items || [];
  const chunkSize = input.chunkSize || 100;

  const chunks = chunkArray(items, chunkSize);
  const metadata = createChunkMetadata(chunks, items);

  return {
    chunks: chunks,
    metadata: metadata
  };
};

// Helper functions below
function chunkArray(array, chunkSize) {
  const chunks = [];

  for (let i = 0; i < array.length; i += chunkSize) {
    chunks.push(array.slice(i, i + chunkSize));
  }

  return chunks;
}

function createChunkMetadata(chunks, originalArray) {
  return {
    total_items: originalArray.length,
    chunk_count: chunks.length,
    items_per_chunk: chunks.map(chunk => chunk.length),
    estimated_payload_size: estimatePayloadSize(chunks)
  };
}

function estimatePayloadSize(chunks) {
  try {
    const jsonString = JSON.stringify(chunks);
    return jsonString.length;
  } catch (error) {
    return -1;
  }
}

