  const _ = require('lodash');

  const items = input.items || [];
  const config = input.config || {};

  const processed = processWithLodash(items, config, _);
  const grouped = groupResults(processed, _);
  const summary = createSummary(grouped, _);

  return {
    processed: processed,
    grouped: grouped,
    summary: summary
  };
};

// Helper functions below
function processWithLodash(items, config, _) {
  return _.flow([
    items => _.filter(items, item => item.active),
    items => _.map(items, item => enrichItem(item, config)),
    items => _.sortBy(items, ['priority', 'created_at']),
    items => _.take(items, config.maxItems || 1000)
  ])(items);
}

function enrichItem(item, config) {
  return {
    ...item,
    calculated_score: calculateScore(item),
    category: determineCategory(item),
    enriched_at: new Date().toISOString()
  };
}

function calculateScore(item) {
  return (item.value || 0) * (item.weight || 1);
}

function determineCategory(item) {
  if (item.score > 100) return 'high';
  if (item.score > 50) return 'medium';
  return 'low';
}

function groupResults(processed, _) {
  return _.groupBy(processed, 'category');
}

function createSummary(grouped, _) {
  return _.mapValues(grouped, items => ({
    count: items.length,
    total_score: _.sumBy(items, 'calculated_score'),
    avg_score: _.meanBy(items, 'calculated_score')
  }));
}

