/**
 * Date processing with moment-timezone
 */
exports.step = function(input, fileInput) {
  const moment = require('moment-timezone');

  const dates = input.dates || [];
  const timezone = input.timezone || 'UTC';

  const processed = processDates(dates, timezone, moment);
  const ranges = generateDateRanges(input.startDate, input.endDate, moment);

  return {
    processed_dates: processed,
    date_ranges: ranges,
    current_timestamp: moment().tz(timezone).toISOString()
  };
};

// Helper functions below
function processDates(dates, timezone, moment) {
  return dates
    .map(dateStr => parseDateSafely(dateStr, moment))
    .filter(parsed => parsed.isValid())
    .map(date => formatDate(date, timezone));
}

function parseDateSafely(dateString, moment) {
  const formats = ['YYYY-MM-DD', 'MM/DD/YYYY', 'YYYY-MM-DD HH:mm:ss'];

  for (const format of formats) {
    const parsed = moment(dateString, format);
    if (parsed.isValid()) {
      return parsed;
    }
  }

  return moment(dateString);
}

function formatDate(momentDate, timezone) {
  return {
    iso: momentDate.toISOString(),
    formatted: momentDate.tz(timezone).format('YYYY-MM-DD HH:mm:ss'),
    unix: momentDate.unix(),
    day_of_week: momentDate.format('dddd')
  };
}

function generateDateRanges(startDate, endDate, moment) {
  const ranges = [];
  const start = moment(startDate);
  const end = moment(endDate);
  const intervalDays = 30;

  let current = start.clone();

  while (current.isBefore(end)) {
    const rangeEnd = moment.min(current.clone().add(intervalDays, 'days'), end);
    ranges.push({
      start: current.format('YYYY-MM-DD'),
      end: rangeEnd.format('YYYY-MM-DD'),
      days: rangeEnd.diff(current, 'days')
    });
    current = rangeEnd.add(1, 'day');
  }

  return ranges;
}

