/**
 * Cryptographic operations with crypto module
 */
exports.step = function(input, fileInput) {
  const crypto = require('crypto');

  const data = input.data;
  const items = input.items || [];

  const hashed = hashData(data, crypto);
  const withIds = addUniqueIds(items, crypto);

  return {
    hashed_data: hashed,
    items_with_ids: withIds
  };
};

// Helper functions below
function hashData(data, crypto) {
  const jsonString = JSON.stringify(data);
  const fullHash = crypto.createHash('sha256').update(jsonString).digest('hex');
  const shortHash = fullHash.substring(0, 8);

  return {
    full_hash: fullHash,
    short_hash: shortHash,
    algorithm: 'sha256'
  };
}

function addUniqueIds(items, crypto) {
  return items.map(item => ({
    ...item,
    unique_id: crypto.randomUUID(),
    hash: generateItemHash(item, crypto)
  }));
}

function generateItemHash(item, crypto) {
  const key = `${item.type || ''}_${item.value || ''}_${item.timestamp || ''}`;
  return crypto.createHash('sha256').update(key).digest('hex').substring(0, 12);
}

