/**
 * URL parsing and construction
 */
exports.step = function(input, fileInput) {
  const { URL } = require('url');

  const urlString = input.url;
  const params = input.params || {};

  const parsed = parseUrl(urlString, URL);
  const constructed = buildUrl(input.baseUrl, params, URL);

  return {
    parsed_url: parsed,
    constructed_url: constructed
  };
};

// Helper functions below
function parseUrl(urlString, URL) {
  try {
    const parsed = new URL(urlString);

    const params = {};
    parsed.searchParams.forEach((value, key) => {
      params[key] = value;
    });

    return {
      protocol: parsed.protocol,
      hostname: parsed.hostname,
      pathname: parsed.pathname,
      search_params: params,
      full_url: parsed.toString()
    };
  } catch (error) {
    return {
      error: 'Invalid URL',
      message: error.message
    };
  }
}

function buildUrl(baseUrl, params, URL) {
  const url = new URL(baseUrl);

  Object.entries(params).forEach(([key, value]) => {
    url.searchParams.append(key, value);
  });

  return url.toString();
}

