/**
 * Buffer encoding and decoding operations
 */
exports.step = function(input, fileInput) {
  const { Buffer } = require('buffer');

  const textData = input.text;
  const base64Data = input.base64;

  const encoded = encodeToBase64(textData, Buffer);
  const decoded = decodeFromBase64(base64Data, Buffer);

  return {
    encoded: encoded,
    decoded: decoded
  };
};

// Helper functions below
function encodeToBase64(text, Buffer) {
  if (!text) return null;

  const buffer = Buffer.from(text, 'utf8');
  const base64 = buffer.toString('base64');

  return {
    original_length: text.length,
    encoded_length: base64.length,
    base64: base64
  };
}

function decodeFromBase64(base64String, Buffer) {
  if (!base64String) return null;

  try {
    const buffer = Buffer.from(base64String, 'base64');
    const text = buffer.toString('utf8');

    return {
      decoded_text: text,
      decoded_length: text.length
    };
  } catch (error) {
    return {
      error: 'Failed to decode base64',
      message: error.message
    };
  }
}
